                value={query}
                onChange={e => setQuery(e.target.value)}
                autoComplete="off" spellCheck="false"
              />
              {loadingSugg && <span className="search-spinner" />}
            </div>

            {suggestions.length > 0 && (
              <div className="suggestions">
                {suggestions.map(p => (
                  <button key={p.id} className="suggestion-item" onClick={() => selectPolitician(p)}>
                    <span className="sug-flag">{COUNTRY_FLAGS[p.country_code] || "??"}</span>
                    <span className="sug-info">
                      <span className="sug-name">{p.full_name}</span>
                      <span className="sug-meta">{p.role} - {p.country}</span>
                    </span>
                    <span className="sug-party">{p.party}</span>
