                <button key={p.slug} className="trending-chip" onClick={() => selectPolitician(p)}>
                  {COUNTRY_FLAGS[p.country_code] || "??"} {p.full_name} <span>{p.party}</span>
                </button>
              ))}
            </div>
          </section>
        )}

        {politician && (
          <main className="main">
            <div className="pol-header">
              <div className="pol-avatar">{politician.full_name[0]}</div>
              <div className="pol-info">
                <h2>{politician.full_name}</h2>
                <div className="pol-badges">
                  <span className="badge badge-party">{politician.party}</span>
                  {politician.state && politician.state !== "-" && (
                    <span className="badge badge-state">{politician.state}</span>
                  )}
                  <span className="badge badge-country">{politician.country}</span>
                  <span className="badge badge-role">{politician.role}</span>
                </div>
              </div>
            </div>

            <nav className="tabs">
              {SECTIONS.map(s => {
                const ck = s.key + "_" + lang;
                return (
                  <button key={s.key}
                    className={"tab" + (activeSection === s.key ? " active" : "")}
                    onClick={() => loadSection(s.key)}>
                    {s.icon} {s.label[lang]}
                    {sectionCache[ck] && <span className="tab-dot" />}
                  </button>
                );
              })}
            </nav>

            <div className="panel">
              <div className="panel-head">
                <span className="panel-title">
                  {SECTIONS.find(s => s.key === activeSection) && SECTIONS.find(s => s.key === activeSection).icon}{" "}
                  {SECTIONS.find(s => s.key === activeSection) && SECTIONS.find(s => s.key === activeSection).label[lang]}
                  {current && current.meta && current.meta.cached && <span className="cache-tag">{t.cached}</span>}
                </span>
                <span className="panel-model">{t.model}</span>
              </div>

              <div className="panel-body">
                {loadingSection ? (
                  <div className="state-loading">
                    <div className="spinner" />
                    <div className="loading-text">{t.loading}</div>
                  </div>
                ) : error ? (
                  <div className="state-error"><div>[!]</div><div>{error}</div></div>
                ) : current ? (
                  <div>
                    <div className="ai-text">
                      {typing
                        ? <TypewriterText text={current.ai_response} onDone={() => setTyping(false)} />
                        : current.ai_response}
                    </div>
                    {current.legal_records && current.legal_records.length > 0 && (
                      <div className="legal-records">
                        <div className="legal-records-title">{t.legalFound}</div>
                        {current.legal_records.map((r, i) => (
                          <div key={i} className={"legal-item legal-item--" + r.status}>
                            <div className="legal-item-head">
                              <span className="legal-badge">{r.type.replace(/_/g, " ").toUpperCase()}</span>
                              <span className="legal-court">{r.court}</span>
                              {r.year && <span className="legal-year">{r.year}</span>}
                            </div>
                            <div className="legal-subject">{r.subject}</div>
                            {r.source_url && r.source_url !== "#" && (
                              <a href={r.source_url} target="_blank" rel="noopener noreferrer" className="legal-link">
                                {lang === "en" ? "View official source" : "Ver fonte oficial"}
                              </a>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                    {current.external_links && current.external_links.length > 0 && (
                      <div className="external-links">
                        <div className="external-links-title">{t.officialLinks}</div>
                        <div className="external-links-grid">
                          {current.external_links.map((l, i) => (
                            <a key={i} href={l.url} target="_blank" rel="noopener noreferrer" className="ext-link-card">
                              <span className="ext-link-label">{l.label}</span>
                              <span className="ext-link-desc">{l.description}</span>
                            </a>
                          ))}
                        </div>
                      </div>
                    )}
                    {current.public_data && current.public_data.length > 0 && (
                      <div className="public-data">
                        <div className="public-data-title">{t.officialData}</div>
                        {current.public_data.map((d, i) => (
                          <div key={i} className="public-data-item">
                            <span className="pd-source">{d.source}</span>
                            <span className="pd-title">{d.title}</span>
