                  </div>
                ) : (
                  <div className="state-empty">
                    <div className="empty-icon">[?]</div>
                    <p>{t.emptyTitle}</p>
                  </div>
                )}
              </div>

              {current && (
                <div className="panel-footer">
                  <span>{t.sources}</span>
                  {["TSE", "Camara", "Congress.gov", "Knesset", "TCU", "STF"].map(s => (
                    <span key={s} className="source-chip">{s}</span>
                  ))}
                  {current.meta && <span className="meta-tokens">{current.meta.tokens} {t.tokens}</span>}
                </div>
              )}
            </div>
          </main>
        )}

        {!politician && (
          <div className="empty-hero">
            <div className="empty-hero-icon">[*]</div>
            <h3>{t.heroTitle}</h3>
            <p>{t.heroSub}</p>
          </div>
        )}

        <footer className="footer">{t.disclaimer}</footer>
      </div>
    </>
  );
